#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long t,b1,b2,f1,f2;
    node():b1(0),b2(0),f1(0),f2(0){}
}a[100010];
long long dis[3000010],n,m;
bool vis[3000010];
char s[100010];
void spfa()
{
    memset(dis,0x3f,sizeof(dis));
    long long st=(1<<n)-1;
    queue<long long> q;
    q.push(st);
    dis[st]=0;
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        vis[t]=0;
        for(long long i=1;i<=m;i++)
        {
            if((t&a[i].b1)==a[i].b1&&(t&a[i].b2)==0)
            {
                long long v=((t|a[i].f1)^a[i].f1)|a[i].f2;
                if(dis[v]>dis[t]+a[i].t)
                {
                    dis[v]=dis[t]+a[i].t;
                    if(!vis[v])
                    {
                        vis[v]=1;
                        q.push(v);
                    }
                }
            }
        }
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%s",&a[i].t,s+1);
        for(long long j=1;j<=n;j++)
        {
            if(s[j]=='+')
            {
                a[i].b1|=(1<<(j-1));
            }
            else if(s[j]=='-')
            {
                a[i].b2|=(1<<(j-1));
            }
        }
        scanf("%s",s+1);
        for(long long j=1;j<=n;j++)
        {
            if(s[j]=='+')
            {
                a[i].f2|=(1<<(j-1));
            }
            else if(s[j]=='-')
            {
                a[i].f1|=(1<<(j-1));
            }
        }
    }
    spfa();
    if(dis[0]>1e18)
    {
        printf("0");
        return 0;
    }
    printf("%lld",dis[0]);
    return 0;
}
